mapper.select:
SELECT wr.id, wr.medicine_id, m.medicine_code, m.medicine_name, wr.batch_no, wr.warning_type, wr.warning_level, wr.warning_message, wr.status, wr.created_at, wr.handled_at FROM warning_record wr INNER JOIN medicine m ON wr.medicine_id = m.id
AND wr.warning_type = #{warningType}
AND wr.status = #{status}
ORDER BY wr.created_at DESC, wr.id DESC
